import '../lib/audit_event.dart';
import '../lib/audit_order.dart';
import '../lib/audit_pager.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final tiedAt = DateTime.utc(2026, 4, 20, 12);
  final alpha = AuditEvent(id: 'evt-a', occurredAt: tiedAt, action: 'opened');
  final beta = AuditEvent(id: 'evt-b', occurredAt: tiedAt, action: 'closed');
  check(
    compareAuditEvents(alpha, beta) < 0,
    'equal instants retain record identity ordering',
  );

  final older = AuditEvent(
    id: 'evt-c',
    occurredAt: DateTime.utc(2026, 4, 20, 11),
    action: 'archived',
  );
  final events = <AuditEvent>[beta, older, alpha];
  final pager = AuditPager();
  final first = pager.page(events, limit: 1);
  final second = pager.page(events, limit: 1, after: first.nextCursor);
  check(
    first.events.single.id == 'evt-a',
    'starts at the first total-order key',
  );
  check(
    second.events.single.id == 'evt-b',
    'a continuation retains peers from the boundary instant',
  );

  print('feedback tests passed');
}
